class Solution:
    def isPerfectMaze(self, maze, n, m):
        if n == 1 and m == 1:
            return maze[0][0] == 1

        stack = [(0, 0, 0)]
        visited = [[False]*m for _ in range(n)]
        while stack:
            i, j, depth = stack.pop()
            if i < 0 or j < 0 or i >= n or j >= m or visited[i][j] or maze[i][j] == 0:
                continue
            visited[i][j] = True
            if depth == n * m - 1:
                return True
            stack.append((i, j, depth + 1))
            stack.append((i - 1, j, depth + 1))
            stack.append((i + 1, j, depth + 1))
            stack.append((i, j - 1, depth + 1))
            stack.append((i, j + 1, depth + 1))
        return False

