#include <iostream>
#include <vector>

using namespace std;

class Solution {
public:
    bool isPerfectMaze(vector<vector<int>>& maze, int n, int m) {
        if (n == 1 && m == 1) return maze[0][0] == 1;

        vector<vector<bool>> visited(n, vector<bool>(m, false));
        stack<pair<int, int>> stack;
        stack.push({0, 0});
        int depth = 0;
        while (!stack.empty()) {
            int i = stack.top().first, j = stack.top().second;
            stack.pop();
            if (i < 0 || j < 0 || i >= n || j >= m || visited[i][j] || maze[i][j] == 0) {
                continue;
            }
            visited[i][j] = true;
            if (depth == n * m - 1) {
                return true;
            }
            stack.push({i, j});
            stack.push({i - 1, j});
            stack.push({i + 1, j});
            stack.push({i, j - 1});
            stack.push({i, j + 1});
            depth++;
        }
        return false;
    }
};
